<?php require 'config.php'; $msg=isset($_GET['created'])?'Account created. Please login.':''; if($_SERVER['REQUEST_METHOD']==='POST'){ verify_csrf(); $email=strtolower(trim($_POST['email']??'')); $pass=$_POST['password']??''; $st=$pdo->prepare('SELECT * FROM users WHERE email=?');$st->execute([$email]);$u=$st->fetch(); if($u && password_verify($pass,$u['password_hash'])){session_regenerate_id(true);$_SESSION['user_id']=$u['id'];$_SESSION['user_name']=$u['name'];$pdo->prepare('UPDATE users SET last_login_at=NOW() WHERE id=?')->execute([$u['id']]);log_activity($pdo,'user_login','Customer login',null,$u['id']);redirect('/dashboard.php');} else {$msg='Invalid login details.';} } ?>
<!doctype html><html><head><title>Login</title><link rel="stylesheet" href="/style.css"></head><body><div class="top"><div class="brand">Karacraft Hosting</div><div class="nav"><a href="/signup.php">Signup</a></div></div><div class="card form"><h1>Customer Login</h1><?php if($msg):?><div class="alert"><?=h($msg)?></div><?php endif;?><form method="post"><?=csrf_field()?><label>Email</label><input name="email" type="email" required><label>Password</label><input name="password" type="password" required><button class="btn">Login</button><p><a href="/forgot_password.php">Forgot password?</a></p></form></div></body></html>
